import type { RefObject } from 'react';
/**
 * 分析一下内容高度变化会不会影响 scrollbar 的宽度
 * 1. 系统常驻滚动条，overflow: overlay，设置 webkit-scrollbar，scrollbarWidth 永远都是 0
 * 2. 系统常驻滚动条，overflow: overlay，不设置 webkit-scrollbar，scrollbarWidth 永远都是 0
 * 3. 系统常驻滚动条，overflow: scroll，设置 webkit-scrollbar，scrollbarWidth 永远都是 webkit-scrollbar-width 宽
 * 4. 系统常驻滚动条，overflow: scroll，不设置 webkit-scrollbar，scrollbarWidth 永远都是系统滚动条宽
 * 5. 系统滚动时显示滚动条，overflow: overlay，（不）设置 webkit-scrollbar，scrollbarWidth 永远都是 0
 * 6. 系统滚动时显示滚动条，overflow: scroll，设置 webkit-scrollbar，scrollbarWidth 不会变，是 webkit-scrollbar-width 宽
 * 7. 系统滚动时显示滚动条，overflow: scroll，不设置 webkit-scrollbar，scrollbarWidth 在 mac 上永远是 0，在 window 上永远是系统宽度。（window 不管隐藏还是不隐藏 scroll 的时候都会显示 track，mac 没问题，因为 scroll 和 auto 行为一致都是 0）
 *
 * TODO 7 <--> 4 的切换 mac 可能会有导致表头列分割线对不齐的问题: 此问题在 firefox 上存在，因为 firefox 不支持 webkit-scrollbar
 * 如果不考虑上述情况，就可以用一个 cache 值只计算一次
 * 注意：overlay 的时候 mac 无法进行动态的常驻和非常驻切换，所以相当于不会有 7 <--> 4 问题
 */
export default function useScrollbarColumnWidth(containerRef: RefObject<HTMLElement>): {
    scrollbarSize: {
        right: number;
        bottom: number;
    };
    calculateScrollbarColumnWidth: () => void;
};
